async (params, browser) => {
  // Open Canva templates page
  await browser.open('https://www.canva.com/templates/')

  // Wait for templates to load
  await browser.waitForSelector('a[href*=\'/templates/\'], [role=\'list\'], main', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract trending templates
  const trending_data = await browser.evaluate(`const categories = []; const catEls = document.querySelectorAll('nav a[href*="/templates/"], a[href*="/templates/s/"]'); catEls.forEach(function(el) { const t = el.textContent.trim(); const href = el.getAttribute('href') || ''; if (t && t.length < 80 && !categories.find(c => c.name === t)) { categories.push({ name: t, url: href.startsWith('http') ? href : 'https://www.canva.com' + href }); } }); const templates = []; const seen = new Set(); const templateEls = document.querySelectorAll('a[href*="/templates/"]'); for (let i = 0; i < templateEls.length && templates.length < 20; i++) { const el = templateEls[i]; const href = el.href || ''; if (!href || seen.has(href)) continue; seen.add(href); const ariaLabel = el.getAttribute('aria-label') || ''; const nameEl = el.querySelector('h3, h4, [aria-label]'); const imgEl = el.querySelector('img'); const proEl = el.querySelector('[aria-label*="Pro"], [aria-label*="premium"]'); const title = ariaLabel || (nameEl ? (nameEl.getAttribute('aria-label') || nameEl.textContent.trim()) : ''); if (!title && !imgEl) continue; templates.push({ rank: templates.length + 1, title: title, is_premium: !!proEl, image: imgEl ? imgEl.getAttribute('src') : '', url: href }); } return { categories: categories.slice(0, 15), trending_count: templates.length, templates: templates, url: window.location.href }`)

  return trending_data
}
